function generateIntentHash(key, txnid, amount, productinfo, firstname, email, salt, siDetailsObj = null) {
    // Core parameters
    const params = [key, txnid, amount.toString(), productinfo, firstname, email];

    // Add exactly 10 empty strings for the unused UDFs
    for (let i = 0; i < 10; i++) {
        params.push("");
    }

    // Append si_details if provided
    if (siDetailsObj) {
        params.push(JSON.stringify(siDetailsObj));
    }

    // Append the salt
    params.push(salt);

    // Construct the string and hash it
    const hashString = params.join('|');
    return crypto.createHash('sha512').update(hashString).digest('hex').toLowerCase();
}

function generateCaptureHash(key, command, var1, salt) {
    const hashString = [key, command, var1, salt].join('|');
    return crypto.createHash('sha512').update(hashString).digest('hex').toLowerCase();
}

